use std::cmp::Ordering;

// Define a state for Dijkstra's algorithm
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    xor_sum: i32,
    row: usize,
    col: usize,
}

// Implement Ord and PartialOrd for use in BinaryHeap (Min-Heap based on xor_sum)
// BinaryHeap in Rust is a max-heap, so we reverse the ordering to simulate a min-heap.
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Notice the order: other.xor_sum.cmp(&self.xor_sum) implements a min-heap
        other.xor_sum.cmp(&self.xor_sum)
            .then_with(|| self.row.cmp(&other.row))
            .then_with(|| self.col.cmp(&other.col))
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn solve(grid: Vec<Vec<i64>>) -> i64 {
    let m = grid.len();
    let n = grid[0].len();

    if m == 0 || n == 0 {
        return 0;
    }

    // Distance array: dist[r][c] stores the minimum XOR sum to reach (r, c)
    // Since XOR sums can be up to 2^10 - 1 = 1023, we use a value larger than that for infinity.
    // Max possible XOR sum is less than 2048.
    let infinity = 2048; 
    let mut dist: Vec<Vec<i32>> = vec![vec![infinity; n]; m];

    // Min-Heap for Dijkstra's algorithm
    let mut heap = BinaryHeap::new();

    // Initial state
    let initial_xor = grid[0][0] as i32;
    dist[0][0] = initial_xor;
    heap.push(State { xor_sum: initial_xor, row: 0, col: 0 });

    while let Some(State { xor_sum: current_xor, row: r, col: c }) = heap.pop() {
        // If we found a better path already, skip
        if current_xor > dist[r][c] {
            continue;
        }

        // Check neighbors: right and down
        let neighbors = [(0, 1), (1, 0)]; // (dr, dc)

        for &(dr, dc) in neighbors.iter() {
            let nr = r as isize + dr as isize;
            let nc = c as isize + dc as isize;

            // Check bounds
            if nr >= 0 && nr < m as isize && nc >= 0 && nc < n as isize {
